#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,a[10],b[10],t,fs=0;
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i]>>b[i];
        fs+=100/a[i]*b[i];
    }
    cin>>t;
    if(fs>=t)cout<<"Already Au.";
    else{
        for(int i=1;i<=n;i++){
            if(100-100/a[i]*b[i]+fs<t)cout<<"NaN"<<endl;
            else{
                if((t-fs)%(100/a[i])==0)cout<<(t-fs)/(100/a[i])<<endl;
                else cout<<(t-fs)/(100/a[i])+1<<endl;
            }
        }
    }
    return 0;
}
